defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts

  @doc """
  Displays a blog post with user-generated rich HTML content.

  SECURITY NOTE: We use HtmlSanitizeEx to sanitize user-generated HTML
  rather than raw/1, which would allow XSS attacks. The sanitizer strips
  dangerous tags (script, iframe, object, embed, etc.) and dangerous
  attributes (onclick, onerror, style with expressions, etc.) while
  preserving safe formatting tags.
  """

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok,
     socket
     |> assign(:page_title, post.title)
     |> assign(:post, post)
     |> assign(:sanitized_content, sanitize_html(post.content))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-3xl mx-auto px-4 py-8">
      <article>
        <header class="mb-8">
          <h1 class="text-3xl font-bold mb-2"><%= @post.title %></h1>
          <div class="text-gray-500 text-sm">
            <span>By <%= @post.author.name %></span>
            <span class="mx-2">·</span>
            <time datetime={@post.inserted_at}><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></time>
          </div>
        </header>

        <div class="prose prose-lg">
          <%= @sanitized_content %>
        </div>
      </article>

      <div class="mt-12 border-t pt-8">
        <h2 class="text-xl font-semibold mb-4">Comments</h2>
        <%= for comment <- @post.comments do %>
          <div class="mb-4 p-4 bg-gray-50 rounded">
            <p class="font-medium text-sm text-gray-700 mb-1"><%= comment.author_name %></p>
            <div class="text-gray-800"><%= sanitize_html(comment.body) %></div>
          </div>
        <% end %>
      </div>
    </div>
    """
  end

  @doc """
  Sanitizes user-generated HTML content, allowing only safe formatting tags
  and attributes. Returns a Phoenix.HTML.safe tuple so it can be rendered
  without additional escaping, but with dangerous content already stripped.

  Allowed tags: p, br, strong, em, u, s, h1-h6, ul, ol, li, blockquote,
                pre, code, a, img, table, thead, tbody, tr, th, td, hr, span, div, sub, sup

  Allowed attributes: href (with http/https/mailto only), src (http/https only),
                      alt, title, class, id, colspan, rowspan, target, rel

  Strips all: script, iframe, object, embed, form, input, style tags,
              on* event handler attributes, javascript: URIs, data: URIs
  """
  defp sanitize_html(nil), do: ""

  defp sanitize_html(html_content) when is_binary(html_content) do
    html_content
    |> HtmlSanitizeEx.Scrubber.scrub(BlogWeb.Scrubber.RichText)
    |> Phoenix.HTML.raw()
  end
end

defmodule BlogWeb.Scrubber.RichText do
  @moduledoc """
  Custom HTML scrubber for rich text blog content.
  Allows safe formatting tags while stripping all potentially dangerous content.
  """

  require HtmlSanitizeEx.Scrubber.Meta
  alias HtmlSanitizeEx.Scrubber.Meta

  # Strip comments
  Meta.strip_comments()

  # Strip dangerous tags entirely (including their content)
  Meta.strip_everything_not_covered()

  # Allowed text formatting tags (no attributes needed)
  @allowed_tags_no_attrs ~w(p br strong em b i u s strike del ins
    h1 h2 h3 h4 h5 h6 ul ol li blockquote pre code hr sub sup
    table thead tbody tfoot tr th td dd dt dl figure figcaption)

  for tag <- @allowed_tags_no_attrs do
    Meta.allow_tag_with_these_attributes(tag, ["class", "id"])
  end

  # Allow <div> and <span> with class and id only
  Meta.allow_tag_with_these_attributes("div", ["class", "id"])
  Meta.allow_tag_with_these_attributes("span", ["class", "id"])

  # Allow <a> tags with safe href values only (http, https, mailto)
  Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
  Meta.allow_tag_with_these_attributes("a", ["title", "class", "id", "rel", "target"])

  # Allow <img> tags with safe src values only (http, https)
  Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
  Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "id", "width", "height", "loading"])

  # Table attributes
  Meta.allow_tag_with_these_attributes("th", ["class", "id", "colspan", "rowspan", "scope"])
  Meta.allow_tag_with_these_attributes("td", ["class", "id", "colspan", "rowspan"])

  # Deny everything else
  Meta.strip_everything_not_covered()
end

defmodule BlogWeb.PostLive.FormComponent do
  use BlogWeb, :live_component

  alias Blog.Posts

  @impl true
  def render(assigns) do
    ~H"""
    <div>
      <.simple_form
        for={@form}
        id="post-form"
        phx-target={@myself}
        phx-change="validate"
        phx-submit="save"
      >
        <.input field={@form[:title]} type="text" label="Title" />
        <.input field={@form[:content]} type="textarea" label="Content (HTML allowed)" />

        <div class="mt-4 p-4 bg-yellow-50 border border-yellow-200 rounded text-sm text-yellow-800">
          <p class="font-semibold">Formatting Guide</p>
          <p>You can use HTML tags for formatting:
            <code>&lt;strong&gt;</code>, <code>&lt;em&gt;</code>,
            <code>&lt;h2&gt;</code>-<code>&lt;h6&gt;</code>,
            <code>&lt;ul&gt;</code>, <code>&lt;ol&gt;</code>,
            <code>&lt;blockquote&gt;</code>, <code>&lt;code&gt;</code>,
            <code>&lt;a href="..."&gt;</code>, <code>&lt;img src="..."&gt;</code>
          </p>
          <p class="mt-1 text-yellow-600">Note: Unsafe HTML (scripts, iframes, event handlers) will be automatically removed.</p>
        </div>

        <:actions>
          <.button phx-disable-with="Saving...">Publish Post</.button>
        </:actions>
      </.simple_form>

      <%= if @live_action == :edit do %>
        <div class="mt-6">
          <h3 class="text-lg font-semibold mb-2">Preview</h3>
          <div class="prose border rounded p-4">
            <%= sanitize_preview(@form[:content].value) %>
          </div>
        </div>
      <% end %>
    </div>
    """
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      socket.assigns.post
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    save_post(socket, socket.assigns.action, post_params)
  end

  defp save_post(socket, :new, post_params) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post published successfully")
         |> push_navigate(to: ~p"/posts/#{post}")}

      {:error, %Ecto.Changeset{} = changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end

  defp save_post(socket, :edit, post_params) do
    case Posts.update_post(socket.assigns.post, post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post updated successfully")
         |> push_navigate(to: ~p"/posts/#{post}")}

      {:error, %Ecto.Changeset{} = changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end

  defp sanitize_preview(nil), do: ""

  defp sanitize_preview(content) when is_binary(content) do
    content
    |> HtmlSanitizeEx.Scrubber.scrub(BlogWeb.Scrubber.RichText)
    |> Phoenix.HTML.raw()
  end
end